#include <iostream>
using namespace std;

int main() {
    char operatorSymbol;
    int num1, num2;

    // Input operator and two numbers
    cin >> operatorSymbol;
    cin >> num1 >> num2;

    // Perform the chosen operation
    switch (operatorSymbol) {
        case '+':
            cout << num1 + num2 << endl;
            break;
        case '-':
            cout << num1 - num2 << endl;
            break;
        case '*':
            cout << num1 * num2 << endl;
            break;
        case '/':
            if (num2 != 0) {
                cout << num1 / num2 << endl;
            } else {
                cout << "Error: Division by zero is not allowed." << endl;
            }
            break;
        case '%':
            cout << num1 % num2 << endl;
            break;
        default:
            cout << "Invalid operator! Please use one of the following: +, -, *, /, %" << endl;
    }

    return 0;
}

