code.C:
#include <stdio.h>

int main() {
    char operator;
    int num1, num2;

    scanf(" %c", &operator);  

    scanf("%d %d", &num1, &num2);

        // Perform the chosen operation
        switch (operator) {
            case '+':
                printf("%d\n", num1 + num2);
                break;
            case '-':
                printf("%d\n", num1 - num2);
                break;
            case '*':
                printf("%d", num1 * num2);
                break;
            case '/':
                if (num2 != 0) {
                    printf("%d\n", num1 / num2);
                } else {
                    printf("Error: Division by zero is not allowed.\n");
                }
                break;
            case '%':
                // Check if num1 and num2 are integers for modulus operation
                if ((int)num1 == num1 && (int)num2 == num2) {
                    // Perform modulus if both numbers are integers
                    printf("%.d\n", (int)num1 % (int)num2);
                } else {
                    printf("Error: Modulus operation requires both numbers to be integers.\n");
                }
                break;    
            default:
                printf("Invalid operator! Please use one of the following: +, -, *, /, %\n");
        }
    return 0;
}

